INSERT INTO DataCode ([Item Name],[Short Name],Unit,[Scale],SectorCode,GeoAreaCode,FrequencyCode,SecurityLevel,[Source],Notes,DepartmentCode,DivisionId,KeyWords,Status,CreatedBy,CreatedOn,ModifiedBy,ModifiedOn,isQuarterStartApril,TopicId,DelayInWords) VALUES
	 (N'Road Network-Class A Roads',N'Road',N'Kilometres',N'',N'R',N'N',N'A',0,N'Road Development Authority',N'“A” Class – All roads within the network of Trunk Roads connecting the national capital with the provincial capitals and also connecting these capitals with one another. Also included are other major roads (all roads paved and bitumen surfaced with carriage way between 24ft. to 36ft. and platform width 36ft. to 56ft.). Latest data is accessible via the CBSL website (https://www.cbsl.gov.lk/en/statistics/economic-and-social-statistics)',13,5,N'Road,Road Network,Class A',1,NULL,NULL,N'STDADMIN','2025-03-21 15:13:32.637',0,56,N'End of August'),
	 (N'Road Network-Class B Roads',N'Road',N'Kilometres',N'',N'R',N'N',N'A',0,N'Road Development Authority',N'“B” Class – Main roads connecting other important towns and also providing important links within the trunk route system (Metalled and bitumen with a small percentage gravelled). Latest data is accessible via the CBSL website (https://www.cbsl.gov.lk/en/statistics/economic-and-social-statistics)',13,5,N'Road,Road Network,Class B',1,NULL,NULL,N'STDADMIN','2025-03-21 15:39:47.85',0,56,N'End of August'),
