	 (N'Road Kilometerage-Kegalle-Class B',N'Road',N'Kilometres',N'',N'R',N'D',N'A',0,N'Road Development Authority',N'“B” Class – Main roads connecting other important towns and also providing important links within the trunk route system (Metalled and bitumen with a small percentage gravelled).',13,5,N'Road,Road Network,Class B,Kegalle',1,NULL,NULL,NULL,NULL,0,56,N'End of August'),
	 (N'Road Kilometerage-Kegalle-Class C',N'Road',N'Kilometres',N'',N'R',N'D',N'A',0,N'Road Development Authority,Provincial Councils',N'“C” Class – Other roads such as agricultural roads and local roads (Single carriage way of 12ft. width and a platform width of 22ft. mostly metalled but with a small percentage gravelled).',13,5,N'Road,Road Network,Class C,Kegalle',1,NULL,NULL,NULL,NULL,0,56,N'End of August'),
	 (N'Road Kilometerage-Kegalle-Class D',N'Road',N'Kilometres',N'',N'R',N'D',N'A',0,N'Road Development Authority,Provincial Councils',N'“D” Class – Gravelled road with 8ft. – 10ft. width surface generally motorable during dry weather only.',13,5,N'Road,Road Network,Class D,Kegalle',1,NULL,NULL,NULL,NULL,0,56,N'End of August'),
	 (N'Road Kilometerage-Kegalle-Expressways',N'Road',N'Kilometres',N'',N'R',N'D',N'A',0,N'Road Development Authority,Provincial Councils',N'',13,5,N'Road,Road Network,Expressways,Highways,Kegalle',1,NULL,NULL,NULL,NULL,0,56,N'End of August');
