	 (N'Central Government - Debt - Foreign',N'Foreign Debt',N'LKR',N'Rs. million',N'F',N'N',N'Q',0,N'Ministry of Finance / CBSL',N'The debt data since April 2022 are highly provisional as the outstanding central government debt excludes several overdue debt service payments after April 12, 2022, the date of which the Interim Policy regarding the servicing of Sri Lanka’s external public debt was announced by the Ministry of Finance, Economic Stabilization and National Policies. These debt service payments include overdue interest payments of affected debt which deemed to be capitalised as per the Interim Policy. And it excluded the value of principal payments yet to be settled in relation to Sri Lanka Development Bonds from April 2022 till end 2022.',3,14,N'Debt',1,NULL,NULL,N'ERDADMIN','2023-06-16 14:18:47.24',0,118,N'Two months after the end of Quarter'),
	 (N'Central Government - Debt - Domestic',N'Domestic Debt',N'LKR',N'Rs. million',N'F',N'N',N'Q',0,N'Ministry of Finance / CBSL',N'The debt data since April 2022 are highly provisional as the outstanding central government debt excludes several overdue debt service payments after April 12, 2022, the date of which the Interim Policy regarding the servicing of Sri Lanka’s external public debt was announced by the Ministry of Finance, Economic Stabilization and National Policies. These debt service payments include overdue interest payments of affected debt which deemed to be capitalised as per the Interim Policy. And it excluded the value of principal payments yet to be settled in relation to Sri Lanka Development Bonds from April 2022 till end 2022.',3,14,N'Debt',1,NULL,NULL,N'ERDADMIN','2023-06-16 14:19:13.033',0,118,N'Two months after the end of Quarter'),
